#$pyFunction
def GetLSProData(page_data, Cookie_Jar, m, url=''):
    from resources.lib.modules import client
    import xbmc, xbmcgui, html, re
    matches = re.findall(
        r"""<a\s+href=['"]([^'"]+)['"][^>]*class=['"][^'"]*custom-button[^'"]*['"][^>]*>(.*?)</a>""",
        page_data,
        re.I | re.S
    )
    results = []
    for href, name in matches:
        name = html.unescape(re.sub(r'<[^>]+>', '', name)).strip()
        if href and name:
            results.append((href, name))
    if not results:
        xbmc.log('WP playurl: no buttons found', xbmc.LOGWARNING)
        return
    if len(results) == 1:
        choice = 0
    else:
        choice = xbmcgui.Dialog().select('Choose Stream', [name for href, name in results])
    if choice == -1:
        return
    href, name = results[choice]
    return [(href, name)]

